sql:
SELECT error_id, error_value, calculation_date
FROM error_metrics
WHERE error_value > (SELECT AVG(error_value) FROM error_metrics);

SELECT version_description 
FROM forecast_versions 
WHERE version_id = 0;

SELECT * 
FROM true_data_versions 
WHERE true_id NOT IN (SELECT true_id FROM true_data);

SELECT SUM(true_cases) AS total_disease_cases
FROM true_data
WHERE year > 2015;

SELECT * 
FROM forecast_data 
WHERE forecast_cases >= (
    SELECT AVG(true_cases) 
    FROM true_data
);

SELECT COUNT(DISTINCT user_id)
FROM access_logs
WHERE data_id IN (SELECT forecast_id FROM forecast_data);

SELECT disease_id, SUM(true_cases) AS total_cases
FROM true_data
GROUP BY disease_id;

external_knowledge:
- 'initial prediction' refers to the forecast_id = 1;
- 'first mentioned illness' corresponds to disease_id = 1;
- 'predicted case numbers' are interpreted as forecast_cases.
